import React from 'react'
import {useState} from 'react'

function App() {
  const [click,setClick] = useState(false);

  function disableButton()
  {
    setClick(true);

  }
  return (
    <>
    
    <button 
      disabled={click}
      onClick={disableButton}> 
        Click Me!!
      </button>
      </>
      
    
    
  )
}

export default App
